WITH MEMBER [Measures].[Combined Gross Profit Margin] AS
    (Sum(
        {
            [Sales Channel].[Sales Channel].&[Internet],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[Gross Profit]
    ))
    /
    (Sum(
        {
            [Sales Channel].[Sales Channel].&[Internet],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[Sales Amount]
    ))
SELECT {[Measures].[Combined Gross Profit Margin]} ON COLUMNS
FROM [Adventure Works]

SELECT {[Measures].[Gross Profit Margin]} ON COLUMNS
FROM [Adventure Works]
WHERE ({[Sales Channel].[Sales Channel].&[Internet], [Sales Channel].[Sales Channel].&[Reseller]});
